import dspy

def run_assertions(prediction, example):
    assertions = {
        'non_empty': lambda p: len(p.strip()) > 0,
        'no_hallucination': lambda p: not any(word in p.lower() for word in ['i think', 'probably', 'maybe']),
        'json_valid': lambda p: dspy.evaluate.answer_exact_match(p, example.answer),
        'length_reasonable': lambda p: 10 < len(p) < 500
    }

    results = {name: assert_fn(prediction) for name, assert_fn in assertions.items()}
    passed = sum(results.values())

    return {
        'passed': passed,
        'total': len(assertions),
        'violations': [k for k,v in results.items() if not v],
        'failed': passed != len(assertions)
    }

