import dspy

from typing import Callable

def assertion_wrapper(module: dspy.Module, assertions: list):
    class AssertingModule(dspy.Module):
        def __init__(self):
            super().__init__()
            self.module = module

        def forward(self, **kwargs):
            prediction = self.module(**kwargs)

            for assertion in assertions:
                if not assertion(prediction):
                    # Retry with different temperature
                    kwargs['temperature'] = 0.9
                    prediction = self.module(**kwargs)

            return prediction

    return AssertingModule()

import dspy
from pydantic import BaseModel, validator

class TypedDSPyModule(dspy.Module):
    output_type: type[BaseModel] = None

    def forward(self, **kwargs):
        raw_output = super().forward(**kwargs)
        parsed = self.output_type.model_validate(raw_output)
        return dspy.Prediction(output=parsed.model_dump())

